const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const app_url = cleanArg('{app_url}');
const app_id = cleanArg('{app_id}');
const country = (cleanArg('{country}') || 'us').toLowerCase();
let target;
if (app_url) { target = app_url; } else if (app_id) { target = `https://apps.apple.com/${encodeURIComponent(country)}/app/id${encodeURIComponent(app_id)}`; } else { return { error: 'must provide app_id or app_url' }; }
setTimeout(() => window.location.assign(target), 0);
return { redirected: true, target };

const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const mode = cleanArg('{mode}').toLowerCase() || 'with-reviews';
if (mode !== 'full') { return { skipped: true, mode }; }
const link = document.querySelector("a[href*='see-all=reviews']");
if (!link) { return { skipped: true, reason: 'no see-all link' }; }
const target = link.href;
setTimeout(() => window.location.assign(target), 0);
return { redirected: true, target, mode };
